#[test]
fn wrong_override_content_type_on_wml_part_is_a_defect() {
    // ECMA-376 Part 1 §11.3.12 ; ECMA-376 Part 2 (OPC) §7.2.3 ; I-CT-002
    //
    // Daily surface (per the spec's `expectations`): the canonically-typed
    // styles-bearing package opens clean. The harness's make_docx always emits
    // the CORRECT canonical styles Override, so this asserts the positive
    // baseline that a correctly-typed styles part opens without repair. The true
    // save adjudication ("the OUTPUT must never carry a mismatched WML content
    // type") is the oracle/validate_docx question recorded in the spec's oracle
    // field and is intentionally kept out of this daily test.
    let body = r#"<w:p><w:pPr><w:pStyle w:val="Heading1"/></w:pPr><w:r><w:t>Styled body, styles part should be styles-typed.</w:t></w:r></w:p><w:sectPr/>"#;
    let styles = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:style w:type="paragraph" w:styleId="Heading1"><w:name w:val="heading 1"/></w:style></w:styles>"#;
    let b = make_docx(body, &[("word/styles.xml", styles)]);

    assert_opens_clean(
        &b,
        "§11.3.12 + §7.2.3: the styles part canonically content-typed \
         (wordprocessingml.styles+xml, never a mismatched WML type) is conformant; the package \
         must open without repair (ECMA-376 Part 1 §11.3.12; ECMA-376 Part 2 §7.2.3; I-CT-002)",
    );
}

#[test]
fn case_insensitive_extension_default_covers_uppercase_media() {
    // ECMA-376 Part 2 (OPC) §7.2.3 ; ECMA-376 Part 1 §9.1.6
    let body = "<w:p><w:r><w:t>Body with media; uppercase extension must still type.</w:t></w:r></w:p><w:sectPr/>";
    let png_bytes = "\u{0089}PNG\r\n\u{001a}\n";
    let b = make_docx(body, &[("word/media/image1.PNG", png_bytes)]);

    assert_eq!(
        Document::parse(&b)
            .expect("parse")
            .read_accepted()
            .expect("read_accepted")
            .to_text()
            .trim(),
        "Body with media; uppercase extension must still type.",
        "§7.2.3 case-insensitive extension matching + §9.1.6 no untyped parts: a media part with \
         an uppercase extension covered by a lowercase Default must resolve a content type, so the \
         document consumes cleanly without the part being treated as invalid/untyped \
         (ECMA-376 Part 2 §7.2.3; ECMA-376 Part 1 §9.1.6)"
    );

    assert_opens_clean(
        &b,
        "§7.2.3 + §9.1.6: a package whose uppercase-extension media part is covered by a \
         case-insensitively matching Default is conformant and must open without repair \
         (ECMA-376 Part 2 §7.2.3; ECMA-376 Part 1 §9.1.6)",
    );
}
